INSERT INTO `reviews` (`id`, `booking_id`, `user_id`, `hotel_id`, `rating`, `comment`, `created_at`) VALUES
  (1, 25, 27, 45, 5.0, 'Vị trí đắc địa giữa trung tâm, đi bộ đến phố cổ chỉ 5 phút.', '2026-01-12 00:00:00'),
  (2, 79, 20, 9, 5.0, 'Trải nghiệm tuyệt vời, đáng đồng tiền. Spa rất thư giãn.', '2026-03-29 00:00:00'),
  (3, 20, 2, 12, 4.5, 'Bữa sáng buffet đa dạng, hồ bơi đẹp. Rất hài lòng với chuyến đi.', '2026-03-07 00:00:00'),
  (4, 50, 5, 36, 3.0, 'Tiếng ồn từ đường phố lớn, khó ngủ. Nhân viên chưa thân thiện.', '2026-01-17 00:00:00'),
  (5, 43, 16, 49, 5.0, 'Phòng sạch sẽ, view tuyệt vời. Vị trí thuận tiện, đi lại dễ dàng.', '2026-02-04 00:00:00'),
  (6, 3, 20, 23, 3.5, 'Tổng thể chấp nhận được với mức giá này. Cần cải thiện dịch vụ.', '2026-03-25 00:00:00'),
  (7, 1, 23, 1, 5.0, 'Trải nghiệm tuyệt vời, đáng đồng tiền. Spa rất thư giãn.', '2026-03-02 00:00:00'),
  (8, 75, 4, 21, 5.0, 'Trải nghiệm tuyệt vời, đáng đồng tiền. Spa rất thư giãn.', '2026-02-04 00:00:00'),
  (9, 56, 23, 47, 4.0, 'Khách sạn ổn, không có gì đặc biệt. Phòng ốc sạch sẽ là được.', '2026-04-06 00:00:00'),
  (10, 52, 14, 42, 5.0, 'Bữa sáng buffet đa dạng, hồ bơi đẹp. Rất hài lòng với chuyến đi.', '2026-01-29 00:00:00'),
  (11, 48, 18, 42, 5.0, 'Vị trí đắc địa giữa trung tâm, đi bộ đến phố cổ chỉ 5 phút.', '2026-03-06 00:00:00'),
  (12, 41, 9, 22, 4.5, 'Bữa sáng buffet đa dạng, hồ bơi đẹp. Rất hài lòng với chuyến đi.', '2026-04-12 00:00:00'),
  (13, 71, 30, 3, 5.0, 'Bữa sáng buffet đa dạng, hồ bơi đẹp. Rất hài lòng với chuyến đi.', '2026-03-10 00:00:00'),
  (14, 55, 14, 10, 5.0, 'Nhân viên nói tiếng Anh tốt, hỗ trợ đặt tour rất tận tình.', '2026-01-17 00:00:00'),
  (15, 24, 22, 38, 5.0, 'Đồ ăn ngon, đặc biệt món phở buổi sáng rất chuẩn vị Hà Nội.', '2026-02-25 00:00:00'),
  (16, 54, 11, 51, 5.0, 'Đồ ăn ngon, đặc biệt món phở buổi sáng rất chuẩn vị Hà Nội.', '2026-01-14 00:00:00'),
  (17, 40, 4, 28, 5.0, 'Khách sạn rất đẹp, nhân viên thân thiện, đồ ăn sáng phong phú. Chắc chắn sẽ quay lại!', '2026-03-17 00:00:00'),
  (18, 32, 20, 43, 4.5, 'Khách sạn rất đẹp, nhân viên thân thiện, đồ ăn sáng phong phú. Chắc chắn sẽ quay lại!', '2026-02-11 00:00:00'),
  (19, 67, 4, 34, 5.0, 'Lễ tân nhiệt tình, check-in nhanh chóng. Phòng rộng và yên tĩnh.', '2026-02-26 00:00:00'),
  (20, 57, 30, 13, 5.0, 'Khách sạn rất đẹp, nhân viên thân thiện, đồ ăn sáng phong phú. Chắc chắn sẽ quay lại!', '2026-03-07 00:00:00'),
  (21, 12, 17, 8, 5.0, 'Bữa sáng buffet đa dạng, hồ bơi đẹp. Rất hài lòng với chuyến đi.', '2026-04-17 00:00:00'),
  (22, 46, 21, 39, 4.0, 'Vị trí tốt nhưng phòng hơi nhỏ so với mong đợi. Giá hợp lý.', '2026-02-25 00:00:00'),
  (23, 4, 20, 44, 4.5, 'Bữa sáng buffet đa dạng, hồ bơi đẹp. Rất hài lòng với chuyến đi.', '2026-01-31 00:00:00'),
  (24, 9, 13, 6, 4.5, 'Trải nghiệm tuyệt vời, đáng đồng tiền. Spa rất thư giãn.', '2026-04-15 00:00:00'),
