INSERT INTO `chat_messages` (`id`, `session_id`, `sender`, `content`, `created_at`) VALUES
  (1, 1, 'user', 'Tôi muốn ở khách sạn trung tâm dưới 1 triệu/đêm', '2026-04-15 08:00:00'),
  (2, 1, 'bot', 'Bạn có yêu cầu gì về tiện ích không? Ví dụ wifi, bữa sáng, bể bơi?', '2026-04-15 08:00:55'),
  (3, 1, 'user', 'Có wifi và bữa sáng là được', '2026-04-15 08:01:10'),
  (4, 1, 'bot', 'Tôi tìm được 8 khách sạn phù hợp, đứng đầu là Hanoi Pearl Hotel với giá 850.000đ/đêm và đánh giá 4.5★', '2026-04-15 08:01:48'),
  (5, 2, 'user', 'Phòng đôi 2 triệu/đêm, view đẹp, yên tĩnh', '2026-04-16 14:00:00'),
